package main

import (
	"context"
	"flag"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime/schema"
	"k8s.io/apimachinery/pkg/runtime/serializer"
	"k8s.io/client-go/dynamic"
	"k8s.io/client-go/kubernetes/scheme"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/apis/runtime/v1alpha1"
	"github.com/volcano-sh/agentcube/pkg/store"
)

const (
	DefaultSandboxIdleTimeout = 15 * time.Minute
	DefaultReadTimeout        = 15 * time.Second
	DefaultIdleTimeout        = 90 * time.Second
)

var (
	port       string
	enableTLS  bool
	tlsCert    string
	tlsKey     string
	enableAuth bool
	debug      bool
)

func init() {
	flag.StringVar(&port, "port", "8080", "Server port")
	flag.BoolVar(&enableTLS, "enable-tls", false, "Enable TLS")
	flag.StringVar(&tlsCert, "tls-cert", "", "TLS certificate path")
	flag.StringVar(&tlsKey, "tls-key", "", "TLS key path")
	flag.BoolVar(&enableAuth, "enable-auth", false, "Enable authentication")
	flag.BoolVar(&debug, "debug", false, "Enable debug mode")
}

func main() {
	flag.Parse()

	if debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	// Initialize store
	storage := store.Storage()

	// Ping store
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := storage.Ping(ctx); err != nil {
		klog.Fatalf("Failed to ping store: %v", err)
	}

	// Create Kubernetes client
	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Fatalf("Failed to get in-cluster config: %v", err)
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		klog.Fatalf("Failed to create dynamic client: %v", err)
	}

	// Create HTTP server
	engine := gin.New()
	engine.Use(gin.Recovery())

	// Health endpoint
	engine.GET("/health", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"status": "healthy"})
	})

	// V1 API routes with middleware
	v1 := engine.Group("/v1")
	v1.Use(loggingMiddleware())
	if enableAuth {
		v1.Use(authMiddleware())
	}

	// Agent runtime routes
	v1.POST("/agent-runtime", createSandboxHandler(dynamicClient, storage, "AgentRuntime"))
	v1.DELETE("/agent-runtime/sessions/:sessionId", deleteSessionHandler(dynamicClient, storage))

	// Code interpreter routes
	v1.POST("/code-interpreter", createSandboxHandler(dynamicClient, storage, "CodeInterpreter"))
	v1.DELETE("/code-interpreter/sessions/:sessionId", deleteSessionHandler(dynamicClient, storage))

	// Start garbage collection
	go startGarbageCollector(storage, dynamicClient, config)

	// Create HTTP server
	server := &http.Server{
		Addr:              ":" + port,
		Handler:           h2c.NewHandler(engine, &http2.Server{}),
		ReadTimeout:       DefaultReadTimeout,
		IdleTimeout:       DefaultIdleTimeout,
		ReadHeaderTimeout: 10 * time.Second,
	}

	// Start server in goroutine
	go func() {
		klog.Infof("Starting workload manager on port %s", port)
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			klog.Fatalf("Failed to start server: %v", err)
		}
	}()

	// Wait for interrupt signal
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	klog.Info("Shutting down server...")

	// Graceful shutdown
	ctx, cancel = context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()
	if err := server.Shutdown(ctx); err != nil {
		klog.Errorf("Server shutdown error: %v", err)
	}

	// Close store
	if err := storage.Close(); err != nil {
		klog.Errorf("Failed to close store: %v", err)
	}

	klog.Info("Server stopped")
}

func createSandboxHandler(dynamicClient dynamic.Interface, storage store.Store, kind string) gin.HandlerFunc {
	return func(c *gin.Context) {
		var req api.CreateSandboxRequest
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"message": "Invalid request body"})
			return
		}

		req.Kind = kind
		if err := req.Validate(); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"message": err.Error()})
			return
		}

		ctx := c.Request.Context()

		// Create sandbox via dynamic client
		var gvr schema.GroupVersionResource
		if kind == "CodeInterpreter" {
			gvr = v1alpha1.SchemeGroupVersion.WithResource("codeinterpreters")
		} else {
			gvr = v1alpha1.SchemeGroupVersion.WithResource("agentruntimes")
		}

		// Store placeholder
		sessionID := generateSessionID()
		sandboxInfo := &store.SandboxInfo{
			SessionID: sessionID,
			Name:      req.Name,
			Namespace: req.Namespace,
			Kind:      kind,
			CreatedAt: time.Now(),
			ExpiresAt: time.Now().Add(DefaultSandboxIdleTimeout),
		}

		if err := storage.StoreSandbox(ctx, sandboxInfo); err != nil {
			klog.Errorf("Failed to store sandbox: %v", err)
			c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
			return
		}

		// TODO: Actually create sandbox resource in Kubernetes
		// This is a simplified implementation

		c.JSON(http.StatusOK, api.CreateSandboxResponse{
			SessionID:   sessionID,
			SandboxID:   sessionID,
			SandboxName: req.Name,
			EntryPoints: []api.EntryPoint{},
		})
	}
}

func deleteSessionHandler(dynamicClient dynamic.Interface, storage store.Store) gin.HandlerFunc {
	return func(c *gin.Context) {
		sessionID := c.Param("sessionId")
		if sessionID == "" {
			c.JSON(http.StatusBadRequest, gin.H{"message": "session ID is required"})
			return
		}

		ctx := c.Request.Context()

		// Load sandbox from store
		sandbox, err := storage.GetSandboxBySessionID(ctx, sessionID)
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, gin.H{"message": "Session ID " + sessionID + " not found, maybe already deleted"})
			return
		}
		if err != nil {
			klog.Errorf("Failed to get sandbox: %v", err)
			c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
			return
		}

		// TODO: Delete actual Kubernetes resources

		// Delete from store
		if err := storage.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
			klog.Errorf("Failed to delete sandbox from store: %v", err)
		}

		c.JSON(http.StatusOK, gin.H{"message": "Sandbox deleted successfully"})
	}
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
		klog.Infof("%s %s %d %v", c.Request.Method, c.Request.URL.Path, c.Writer.Status(), time.Since(start))
	}
}

func authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		auth := c.GetHeader("Authorization")
		if auth == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "Missing authorization header"})
			c.Abort()
			return
		}

		// TODO: Implement proper TokenReview validation
		c.Next()
	}
}

func startGarbageCollector(storage store.Store, dynamicClient dynamic.Interface, config *rest.Config) {
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
		defer cancel()

		now := time.Now()
		inactiveTime := now.Add(-DefaultSandboxIdleTimeout)

		// List expired sessions
		expired, err := storage.ListExpiredSandboxes(ctx, now, 16)
		if err != nil {
			klog.Errorf("Failed to list expired sandboxes: %v", err)
			continue
		}

		// List inactive sessions
		inactive, err := storage.ListInactiveSandboxes(ctx, inactiveTime, 16)
		if err != nil {
			klog.Errorf("Failed to list inactive sandboxes: %v", err)
			continue
		}

		// Merge and deduplicate
		allSessionIDs := make(map[string]bool)
		for _, id := range expired {
			allSessionIDs[id] = true
		}
		for _, id := range inactive {
			allSessionIDs[id] = true
		}

		// Delete each sandbox
		for sessionID := range allSessionIDs {
			sandbox, err := storage.GetSandboxBySessionID(ctx, sessionID)
			if err == store.ErrNotFound {
				continue
			}
			if err != nil {
				klog.Errorf("Failed to get sandbox %s: %v", sessionID, err)
				continue
			}

			// TODO: Delete actual Kubernetes resources

			if err := storage.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
				klog.Errorf("Failed to delete sandbox %s: %v", sessionID, err)
			}
		}
	}
}

func generateSessionID() string {
	return uuid.New().String()
}

